The following program segfaults on amd64:

#include <limits.h>
#include <pthread.h>

static void *
fn(void *arg __unused)
{

        return (NULL);
}

int
main(void)
{
        pthread_t t;
        pthread_attr_t attr;

        (void)pthread_attr_init(&attr);
        (void)pthread_attr_setstacksize(&attr, PTHREAD_STACK_MIN);

        (void)pthread_create(&t, &attr, fn, NULL);
        (void)pthread_join(t, NULL);

        return (0);
}

